package pl.rezerwacjasal.rezerwacjasal.views; import com.vaadin.flow.component.button.Button; import com.vaadin.flow.component.datetimepicker.DateTimePicker; import com.vaadin.flow.component.grid.Grid; import com.vaadin.flow.component.html.*; import com.vaadin.flow.component.notification.Notification; import com.vaadin.flow.component.orderedlayout.VerticalLayout; import com.vaadin.flow.router.*; import jakarta.annotation.security.RolesAllowed; import pl.rezerwacjasal.rezerwacjasal.model.*; import pl.rezerwacjasal.rezerwacjasal.service.RoomReservationService; @Route("rooms") @RouteAlias("") @PageTitle("Rooms") @RolesAllowed("CLIENT") public class RoomsView extends VerticalLayout { private final RoomReservationService service; private final DateTimePicker start=new DateTimePicker("Start"); private final DateTimePicker end=new DateTimePicker("End"); public RoomsView(RoomReservationService service) { this.service=service; Grid<ConferenceRoom> grid=new Grid<>(ConferenceRoom.class,false); grid.addColumn(ConferenceRoom::getName).setHeader("Room"); grid.addColumn(ConferenceRoom::getCapacity).setHeader("Capacity"); grid.addColumn(ConferenceRoom::getPricePerHour).setHeader("Price/h"); grid.addComponentColumn(room -> new Button("Reserve", e -> reserve(room))); grid.setItems(service.getAllRooms()); add(new Anchor("rooms/my","My reservations"), new H2("Conference rooms"), start, end, grid); } private void reserve(ConferenceRoom room) { try { RoomReservation r=service.createReservation(room.getId(), start.getValue(), end.getValue()); Notification.show("Reserved id: "+r.getId()); } catch(RuntimeException ex) { Notification.show(ex.getMessage()); } } }
